const out = [];
for (const item of $input.all()) {
  const sourceId = item.json.source_id;
  const sourceName = item.json.source_name;
  const defaultCategory = item.json.default_category || 'industry_practice';

  // The HTTP Request node returns body either as $json.data (string) or $json directly.
  let xml = '';
  if (typeof item.json === 'string') xml = item.json;
  else if (typeof item.json.data === 'string') xml = item.json.data;
  else if (typeof item.json.body === 'string') xml = item.json.body;
  else if (item.binary && item.binary.data && item.binary.data.data) {
    xml = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
  }
  if (!xml) continue;

  const articles = [];
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = itemRegex.exec(xml)) !== null) {
    const block = m[1];
    const title = (block.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i) || [,''])[1].trim();
    const link = (block.match(/<link[^>]*>([\s\S]*?)<\/link>/i) || [,''])[1].trim();
    const desc = (block.match(/<description[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/i) || [,''])[1].trim();
    const pubDate = (block.match(/<pubDate>([\s\S]*?)<\/pubDate>/i) || [,''])[1].trim();
    if (title && link) articles.push({title, link, description: desc, pubDate});
  }
  if (articles.length === 0) {
    const entryRegex = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
    while ((m = entryRegex.exec(xml)) !== null) {
      const block = m[1];
      const title = (block.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i) || [,''])[1].trim();
      const linkMatch = block.match(/<link[^>]*href="([^"]+)"/i);
      const link = linkMatch ? linkMatch[1] : '';
      const summary = (block.match(/<(?:summary|content)[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/(?:summary|content)>/i) || [,''])[1].trim();
      const updated = (block.match(/<(?:updated|published)>([\s\S]*?)<\/(?:updated|published)>/i) || [,''])[1].trim();
      if (title && link) articles.push({title, link, description: summary, pubDate: updated});
    }
  }

  for (const a of articles) {
    out.push({
      json: {
        source_id: sourceId,
        source_name: sourceName,
        source_kind: 'rss',
        default_category: defaultCategory,
        title: a.title.replace(/<[^>]+>/g, '').slice(0, 500),
        url: a.link,
        published_at: a.pubDate ? (function(){ try { return new Date(a.pubDate).toISOString(); } catch(e){ return null; } })() : null,
        snippet: a.description.replace(/<[^>]+>/g, '').slice(0, 1500)
      }
    });
  }
}
return out;

const inputs = $input.all();
if (inputs.length === 0) return [{json: {startUrls: [], skip: true}}];
const urls = inputs.map(it => ({url: it.json.url}));
return [{json: {
  startUrls: urls,
  maxCrawlDepth: 1,
  maxCrawlPages: 60,
  crawlerType: 'playwright:firefox',
  proxyConfiguration: {useApifyProxy: true, apifyProxyGroups: ['RESIDENTIAL']},
  saveMarkdown: true,
  removeElementsCssSelector: 'nav, footer, aside, .sidebar, .related, header'
}}];

const out = [];
const hostMap = {
  'irs.gov':                 ['irs_newsroom',     'IRS Newsroom',           'tax_regulatory'],
  'fincen.gov':              ['fincen_boi',       'FinCEN BOI',             'tax_regulatory'],
  'firmofthefuture.com':     ['firm_of_future',   'Firm of the Future',     'industry_practice'],
  'karbonhq.com':            ['karbon_blog',      'Karbon Magazine',        'industry_practice'],
  'journalofaccountancy.com':['jofa_news',        'Journal of Accountancy', 'tax_regulatory'],
  'aicpa-cima.com':          ['aicpa_insights',   'AICPA Insights',         'industry_practice'],
  'thetaxadviser.com':       ['tax_adviser',      'The Tax Adviser',        'tax_regulatory'],
  'keeper.app':              ['keeper_blog',      'Keeper',                 'industry_practice'],
  'relayfi.com':             ['relay_blog',       'Relay',                  'industry_practice']
};

for (const it of $input.all()) {
  const data = it.json;
  if (!data || !data.url) continue;
  // Skip the seed/index pages themselves; we want content pages
  let host;
  try { host = new URL(data.url).hostname.replace(/^www\./, ''); } catch(e) { continue; }
  const mapped = hostMap[host] || [host.replace(/\./g, '_'), host, 'industry_practice'];
  const [sourceId, sourceName, defaultCategory] = mapped;

  const text = data.markdown || data.text || '';
  if (text.length < 200) continue;  // discard nav-only pages

  out.push({
    json: {
      source_id: sourceId,
      source_name: sourceName,
      source_kind: 'apify_crawl',
      default_category: defaultCategory,
      title: ((data.metadata && data.metadata.title) || data.title || '').slice(0, 500),
      url: data.url,
      published_at: (data.metadata && (data.metadata.publishedAt || data.metadata.modifiedAt)) || data.loadedTime || null,
      snippet: text.slice(0, 1500)
    }
  });
}
return out;

const out = [];
for (const it of $input.all()) {
  const msg = it.json;
  const headers = (msg.payload && msg.payload.headers) || [];
  const h = (n) => (headers.find(x => x.name === n) || {}).value || '';
  const subject = h('Subject') || msg.subject || '';
  const from = h('From') || msg.from || '';
  const date = h('Date') || (msg.internalDate ? new Date(parseInt(msg.internalDate)).toISOString() : '');
  const snippet = msg.snippet || msg.text || '';

  let sourceId = 'gmail_other';
  let sourceName = 'GovDelivery';
  let category = 'tax_regulatory';
  if (/irs\.gov|govdelivery.*irs/i.test(from)) { sourceId = 'irs_newswire'; sourceName = 'IRS Newswire'; }
  else if (/fincen\.gov/i.test(from)) { sourceId = 'fincen_govdelivery'; sourceName = 'FinCEN'; }
  else if (/treasury\.gov/i.test(from)) { sourceId = 'treasury_press'; sourceName = 'Treasury'; }
  else if (/revenue\.ky\.gov|kyfac/i.test(from)) { sourceId = 'ky_dor'; sourceName = 'Kentucky DOR'; }
  else if (/in\.gov/i.test(from)) { sourceId = 'in_dor'; sourceName = 'Indiana DOR'; }
  else if (/ssa\.gov/i.test(from)) { sourceId = 'ssa_press'; sourceName = 'SSA Press'; category = 'client_smb'; }
  else if (/dol\.gov/i.test(from)) { sourceId = 'dol_govdelivery'; sourceName = 'DOL'; category = 'client_smb'; }

  let url = '';
  const text = (msg.text || snippet || '').toString();
  const linkMatch = text.match(/https?:\/\/[^\s)>"]+/);
  if (linkMatch) url = linkMatch[0];
  if (!url) url = `gmail://message/${msg.id || ''}`;

  if (!subject) continue;

  out.push({
    json: {
      source_id: sourceId,
      source_name: sourceName,
      source_kind: 'gmail',
      default_category: category,
      title: subject.slice(0, 500),
      url,
      published_at: date ? (function(){ try { return new Date(date).toISOString(); } catch(e){ return null; } })() : null,
      snippet: (text || snippet).slice(0, 1500)
    }
  });
}
return out;

const crypto = require('crypto');

function normalizeUrl(u) {
  if (!u) return '';
  try {
    const url = new URL(u);
    const drop = ['utm_source','utm_medium','utm_campaign','utm_content','utm_term','fbclid','gclid','mc_cid','mc_eid','ref','source'];
    drop.forEach(p => url.searchParams.delete(p));
    url.hash = '';
    return url.toString();
  } catch { return u; }
}

const out = [];
for (const it of $input.all()) {
  const j = it.json;
  if (!j || !j.title || !j.url) continue;
  const normUrl = normalizeUrl(j.url);
  const hashInput = `${normUrl}|${j.title.trim().toLowerCase()}`;
  const hash = crypto.createHash('sha256').update(hashInput).digest('hex');
  out.push({json: {...j, url: normUrl, content_hash: hash}});
}
return out;

const seenRows = $input.all().map(i => i.json);
const seenHashes = new Set(seenRows.map(r => r.content_hash));
const allItems = $('Normalize & Hash').all().map(i => i.json);

const cutoff = new Date(Date.now() - 36 * 60 * 60 * 1000);
const noisePattern = /\b(PCAOB|Big 4 audit|SEC enforcement against|Deloitte settl|sanctions designation|OFAC SDN list|Olympics|World Cup)\b/i;
const authoritative = new Set([
  'irs_newsroom','irs_newswire','fincen_boi','fincen_govdelivery','treasury_press',
  'ky_dor','in_dor','indiana_dor','jofa_news','tax_adviser','aicpa_insights','dol_govdelivery'
]);

// Within-batch dedupe (same URL appearing twice across sources)
const withinBatch = new Set();
const out = [];
for (const j of allItems) {
  if (seenHashes.has(j.content_hash)) continue;
  if (withinBatch.has(j.content_hash)) continue;
  withinBatch.add(j.content_hash);
  if (j.published_at) {
    const t = new Date(j.published_at);
    if (!isNaN(t) && t < cutoff) continue;
  }
  const text = `${j.title} ${j.snippet || ''}`;
  if (!authoritative.has(j.source_id) && noisePattern.test(text)) continue;
  out.push({json: j});
}
// Cap to keep Anthropic output under default 8K token budget
return out.slice(0, 60);

const response = $input.first().json;
const ratings = (response.output && response.output.items) || [];
if (!ratings || ratings.length === 0) {
  throw new Error('No items in structured output: ' + JSON.stringify(response).slice(0, 800));
}

const ratingsById = Object.fromEntries(ratings.map(r => [r.id, r]));
const originalItems = $('Build Anthropic Body').first().json.originalItems;

const out = [];
for (const orig of originalItems) {
  const id = orig.content_hash.slice(0, 12);
  const r = ratingsById[id];
  if (!r) continue;
  out.push({
    json: {
      ...orig,
      summary: r.summary,
      category: r.category,
      subcategory: r.subcategory || null,
      importance_score: r.importance_score,
      why_it_matters: r.why_it_matters,
      action_items: r.action_items || [],
      client_comm_candidate: !!r.client_comm_candidate,
      geographic_relevance: r.geographic_relevance || 'general',
      _input_tokens: 0,
      _output_tokens: 0,
      _cache_read_input_tokens: 0,
      _cache_creation_input_tokens: 0
    }
  });
}
return out;

const all = $input.all().map(i => i.json);
all.sort((a, b) => b.importance_score - a.importance_score);

const quotas = {tax_regulatory: 6, industry_practice: 5, client_smb: 3};
const buckets = {tax_regulatory: [], industry_practice: [], client_smb: []};
for (const it of all) {
  const cat = (it.category in buckets) ? it.category : 'industry_practice';
  buckets[cat].push(it);
}

const selected = [];
const seen = new Set();
for (const [cat, min] of Object.entries(quotas)) {
  for (const it of buckets[cat].slice(0, min)) {
    if (!seen.has(it.content_hash)) { selected.push(it); seen.add(it.content_hash); }
  }
}
for (const it of all) {
  if (selected.length >= 20) break;
  if (!seen.has(it.content_hash)) { selected.push(it); seen.add(it.content_hash); }
}
selected.sort((a, b) => b.importance_score - a.importance_score);

const top3 = selected.slice(0, 3);
const rest = selected.slice(3);
const taxItems = rest.filter(i => i.category === 'tax_regulatory');
const industryItems = rest.filter(i => i.category === 'industry_practice');
const clientItems = rest.filter(i => i.category === 'client_smb');

const N8N_BASE = 'https://n8n.clifton.quest';
const FB = (h, s) => `${N8N_BASE}/webhook/brief/feedback?item=${encodeURIComponent(h)}&signal=${s}`;

function esc(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}
function timeAgo(iso) {
  if (!iso) return '';
  const t = new Date(iso); if (isNaN(t)) return '';
  const h = Math.round((Date.now() - t.getTime()) / 3600000);
  if (h < 1) return 'just now'; if (h < 24) return `${h}h ago`;
  return `${Math.round(h / 24)}d ago`;
}

function renderItem(it, n) {
  const actions = (it.action_items || []).length
    ? `<div style="margin-top:6px;font-size:13px;color:#444"><strong>ACTION:</strong> ${esc(it.action_items.join('; '))}</div>` : '';
  const why = it.why_it_matters
    ? `<div style="margin-top:4px;font-size:13px;color:#666;font-style:italic">${esc(it.why_it_matters)}</div>` : '';
  const geo = ['indiana','kentucky'].includes(it.geographic_relevance)
    ? `<span style="background:#fef3c7;color:#92400e;padding:1px 6px;border-radius:3px;font-size:11px;margin-left:4px">${it.geographic_relevance.toUpperCase()}</span>` : '';
  const comm = it.client_comm_candidate
    ? `<span style="background:#dbeafe;color:#1e40af;padding:1px 6px;border-radius:3px;font-size:11px;margin-left:4px">CLIENT COMM</span>` : '';
  return `<div style="margin-bottom:18px;padding-bottom:14px;border-bottom:1px solid #eee">
    <div style="font-weight:600;font-size:15px;line-height:1.35"><span style="color:#999">${n}.</span> ${esc(it.title)}${geo}${comm}</div>
    <div style="font-size:12px;color:#888;margin:3px 0">Score ${it.importance_score} · ${esc(it.source_name)} · ${timeAgo(it.published_at)}</div>
    <div style="font-size:14px;line-height:1.5;color:#222;margin-top:4px">${esc(it.summary)}</div>
    ${why}${actions}
    <div style="margin-top:8px;font-size:12px">
      <a href="${esc(it.url)}" style="color:#2563eb;text-decoration:none">→ Source</a>
      &nbsp;·&nbsp;
      <a href="${FB(it.content_hash,'up')}" style="color:#16a34a;text-decoration:none">👍</a>
      &nbsp;
      <a href="${FB(it.content_hash,'down')}" style="color:#dc2626;text-decoration:none">👎</a>
    </div>
  </div>`;
}
function renderSection(title, items, startN) {
  if (!items.length) return '';
  return `<h2 style="font-size:13px;letter-spacing:0.08em;color:#666;margin:24px 0 12px;text-transform:uppercase;border-top:2px solid #333;padding-top:12px">${title} (${items.length} items)</h2>
    ${items.map((it, i) => renderItem(it, startN + i)).join('')}`;
}

const dateStr = new Date().toLocaleDateString('en-US', {weekday: 'short', month: 'short', day: 'numeric', year: 'numeric'});
const readMin = Math.max(8, Math.round(selected.length * 0.7));
const totalConsidered = all.length;
const totalIncluded = selected.length;

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif">
<div style="max-width:640px;margin:0 auto;background:#fff;padding:24px 22px">
  <div style="border-bottom:3px solid #111;padding-bottom:12px;margin-bottom:18px">
    <div style="font-size:11px;letter-spacing:0.15em;color:#666;text-transform:uppercase">HBF Daily Brief</div>
    <div style="font-size:18px;font-weight:700;margin-top:4px">${dateStr}</div>
    <div style="font-size:12px;color:#888;margin-top:4px">${selected.length} items · ~${readMin} min read</div>
  </div>
  <h2 style="font-size:13px;letter-spacing:0.08em;color:#666;margin:0 0 12px;text-transform:uppercase">Top stories</h2>
  ${top3.map((it, i) => renderItem(it, i + 1)).join('')}
  ${renderSection('Tax & Regulatory', taxItems, 4)}
  ${renderSection('Industry & Practice', industryItems, 4 + taxItems.length)}
  ${renderSection('Client-Facing & SMB', clientItems, 4 + taxItems.length + industryItems.length)}
  <div style="margin-top:30px;padding-top:14px;border-top:1px solid #eee;font-size:11px;color:#999;text-align:center">
    Items considered: ${totalConsidered} · Filtered to: ${totalIncluded}
  </div>
</div>
</body></html>`;

const subject = `HBF Brief · ${dateStr} · ${selected.length} items`;
const usage = all[0] || {};
const totalIn = (usage._input_tokens || 0) + (usage._cache_read_input_tokens || 0) + (usage._cache_creation_input_tokens || 0);
const totalOut = usage._output_tokens || 0;
const cost = (
  ((usage._input_tokens || 0) / 1e6) * 3.0 +
  ((usage._cache_read_input_tokens || 0) / 1e6) * 0.3 +
  ((usage._cache_creation_input_tokens || 0) / 1e6) * 3.75 +
  (totalOut / 1e6) * 15.0
);

return [{
  json: {
    html,
    subject,
    selected,
    allConsidered: all,
    digest_record: {
      digest_date: new Date().toISOString().slice(0, 10),
      item_count: selected.length,
      items: selected.map(s => ({
        hash: s.content_hash, score: s.importance_score, category: s.category,
        source: s.source_id, title: s.title
      })),
      total_input_tokens: totalIn,
      total_output_tokens: totalOut,
      cost_usd: Number(cost.toFixed(4))
    }
  }
}];
